class DataProtector:
    """Handles encryption/hashing of sensitive data before storage."""

    def __init__(self, secret_key: str):
        if not secret_key:
            raise ValueError("ENCRYPTION_KEY environment variable must be set for data protection")
        self.secret_key = secret_key.encode('utf-8')

    def hmac_hash(self, data: str) -> str:
        """Create HMAC hash for data integrity verification."""
        return hmac.new(self.secret_key, data.encode('utf-8'), hashlib.sha256).hexdigest()

    def obfuscate(self, data: str) -> str:
        """
        Obfuscate sensitive data using XOR with HMAC-derived key stream.
        This is a simple obfuscation - for production, use a proper encryption
        library like cryptography (Fernet).
        """
        key_stream = hashlib.pbkdf2_hmac(
            'sha256', self.secret_key, b'redis-cache-salt', 100000, dklen=len(data)
        )
        obfuscated = bytes(a ^ b for a, b in zip(data.encode('utf-8'), key_stream))
        return obfuscated.hex()

    def deobfuscate(self, hex_data: str) -> str:
        """Reverse the obfuscation."""
        data_bytes = bytes.fromhex(hex_data)
        key_stream = hashlib.pbkdf2_hmac(
            'sha256', self.secret_key, b'redis-cache-salt', 100000, dklen=len(data_bytes)
        )
        original = bytes(a ^ b for a, b in zip(data_bytes, key_stream))
        return original.decode('utf-8')

    def hash_for_key(self, identifier: str) -> str:
        """Create a one-way hash suitable for use as a Redis key component."""
        return hashlib.sha256(
            (identifier + self.secret_key.decode('utf-8')).encode('utf-8')
        ).hexdigest()[:32]


class RedisClusterClient:
    """Manages connection to Redis cluster with retry logic and health checks."""

    def __init__(self):
        self._client: Optional[RedisCluster] = None
        self._fallback_client: Optional[redis.Redis] = None
        self._connect()

    def _parse_nodes(self):
        """Parse Redis cluster nodes from configuration."""
        nodes = []
        for node_str in REDIS_NODES.split(","):
            node_str = node_str.strip()
            if ":" in node_str:
                host, port = node_str.rsplit(":", 1)
                nodes.append(ClusterNode(host=host, port=int(port)))
            else:
                nodes.append(ClusterNode(host=node_str, port=6379))
        return nodes

    def _connect(self):
        """Establish connection to Redis cluster."""
        nodes = self._parse_nodes()
        ssl_kwargs = {}
        if REDIS_SSL:
            ssl_kwargs = {
                "ssl": True,
                "ssl_cert_reqs": "required",
            }
            if REDIS_SSL_CERT:
                ssl_kwargs["ssl_certfile"] = REDIS_SSL_CERT
            if REDIS_SSL_KEY:
                ssl_kwargs["ssl_keyfile"] = REDIS_SSL_KEY
            if REDIS_SSL_CA_CERT:
                ssl_kwargs["ssl_ca_certs"] = REDIS_SSL_CA_CERT

        try:
            self._client = RedisCluster(
                startup_nodes=nodes,
                password=REDIS_PASSWORD if REDIS_PASSWORD else None,
                decode_responses=True,
                skip_full_coverage_check=True,
                socket_timeout=5,
                socket_connect_timeout=5,
                retry_on_timeout=True,
                health_check_interval=30,
                **ssl_kwargs
            )
            self._client.ping()
            logger.info("Successfully connected to Redis cluster")
        except Exception as e:
            logger.warning(f"Failed to connect to Redis cluster: {e}. Trying standalone mode.")
            try:
                first_node = nodes[0] if nodes else ClusterNode("localhost", 6379)
                self._fallback_client = redis.Redis(
                    host=first_node.host,
                    port=first_node.port,
                    password=REDIS_PASSWORD if REDIS_PASSWORD else None,
                    decode_responses=True,
                    socket_timeout=5,
                    socket_connect_timeout=5,
                    retry_on_timeout=True,
                    health_check_interval=30,
                    **ssl_kwargs
                )
                self._fallback_client.ping()
                logger.info("Connected to Redis in standalone mode")
            except Exception as e2:
                logger.error(f"Failed to connect to Redis in any mode: {e2}")
                raise

    @property
    def client(self):
        """Return the active Redis client."""
        if self._client:
            return self._client
        if self._fallback_client:
            return self._fallback_client
        raise ConnectionError("No Redis connection available")

    def execute_with_retry(self, operation, *args, max_retries=3, **kwargs):
        """Execute a Redis operation with retry logic."""
        last_exception = None
        for attempt in range(max_retries):
            try:
                return operation(*args, **kwargs)
            except (ConnectionError, TimeoutError) as e:
                last_exception = e
                logger.warning(f"Redis operation failed (attempt {attempt + 1}/{max_retries}): {e}")
                if attempt < max_retries - 1:
                    time.sleep(0.5 * (attempt + 1))
                    try:
                        self._connect()
                    except Exception:
                        pass
            except RedisError as e:
                logger.error(f"Redis error: {e}")
                raise
        raise last_exception

    def health_check(self) -> Dict[str, Any]:
        """Perform health check on Redis connection."""
        try:
            start = time.time()
            self.client.ping()
            latency = (time.time() - start) * 1000

            info = {}
            try:
                cluster_info = self.client.cluster_info() if self._client else self.client.info()
                info = {
                    "mode": "cluster" if self._client else "standalone",
                    "connected": True,
                    "latency_ms": round(latency, 2),
                }
                if self._client:
                    info["cluster_state"] = cluster_info.get("cluster_state", "unknown")
                    info["cluster_known_nodes"] = cluster_info.get("cluster_known_nodes", 0)
            except Exception:
                info = {
                    "mode": "cluster" if self._client else "standalone",
                    "connected": True,
                    "latency_ms": round(latency, 2),
                }
            return info
        except Exception as e:
            return {"connected": False, "error": str(e)}


class CacheService:
    """Core caching service for handling sensitive data storage."""

    def __init__(self, redis_client: RedisClusterClient, protector: DataProtector):
        self.redis = redis_client
        self.protector = protector

    # --- Session Token Management ---

    def create_session(self, user_id: str, metadata: Optional[Dict] = None) -> Dict[str, str]:
        """Create a new session token for a user."""
        session_token = secrets.token_urlsafe(48)
        token_hash = self.protector.hmac_hash(session_token)
        session_key = f"{KEY_PREFIX_SESSION}{token_hash}"

        session_data = {
            "user_id": user_id,
            "created_at": datetime.utcnow().isoformat(),
            "token_hash": token_hash,
        }
        if metadata:
            # Don't store raw metadata - sanitize and limit what's stored
            allowed_fields = {"ip_address", "user_agent", "device_id"}
            safe_metadata = {k: v for k, v in metadata.items() if k in allowed_fields}
            session_data["metadata"] = json.dumps(safe_metadata)

        serialized = json.dumps(session_data)

        def _create():
            pipe = self.redis.client.pipeline()
            pipe.setex(session_key, SESSION_TOKEN_TTL, serialized)
            # Index: map user_id to session keys for management
            user_sessions_key = f"{KEY_PREFIX_SESSION}user:{self.protector.hash_for_key(user_id)}"
            pipe.sadd(user_sessions_key, session_key)
            pipe.expire(user_sessions_key, SESSION_TOKEN_TTL)
            pipe.execute()

        self.redis.execute_with_retry(_create)
        logger.info(f"Session created for user {user_id[:8]}***")

        return {
            "session_token": session_token,
            "expires_in": SESSION_TOKEN_TTL,
        }

    def validate_session(self, session_token: str) -> Optional[Dict]:
        """Validate a session token and return session data."""
        token_hash = self.protector.hmac_hash(session_token)
        session_key = f"{KEY_PREFIX_SESSION}{token_hash}"

        def _validate():
            data = self.redis.client.get(session_key)
            if data:
                # Refresh TTL on access (sliding expiration)
                self.redis.client.expire(session_key, SESSION_TOKEN_TTL)
            return data

        raw_data = self.redis.execute_with_retry(_validate)
        if raw_data:
            session_data = json.loads(raw_data)
            logger.info(f"Session validated for user {session_data['user_id'][:8]}***")
            return session_data
        return None

    def revoke_session(self, session_token: str) -> bool:
        """Revoke a session token."""
        token_hash = self.protector.hmac_hash(session_token)
        session_key = f"{KEY_PREFIX_SESSION}{token_hash}"

        def _revoke():
            # Get session data first to clean up user index
            data = self.redis.client.get(session_key)
            if data:
                session_data = json.loads(data)
                user_id = session_data.get("user_id", "")
                user_sessions_key = f"{KEY_PREFIX_SESSION}user:{self.protector.hash_for_key(user_id)}"
                pipe = self.redis.client.pipeline()
                pipe.delete(session_key)
                pipe.srem(user_sessions_key, session_key)
                pipe.execute()
                return True
            return False

        result = self.redis.execute_with_retry(_revoke)
        logger.info(f"Session revocation: {'success' if result else 'not found'}")
        return result

    def revoke_all_user_sessions(self, user_id: str) -> int:
        """Revoke all sessions for a user."""
        user_sessions_key = f"{KEY_PREFIX_SESSION}user:{self.protector.hash_for_key(user_id)}"

        def _revoke_all():
            session_keys = self.redis.client.smembers(user_sessions_key)
            if session_keys:
                pipe = self.redis.client.pipeline()
                for key in session_keys:
                    pipe.delete(key)
                pipe.delete(user_sessions_key)
                pipe.execute()
                return len(session_keys)
            return 0

        count = self.redis.execute_with_retry(_revoke_all)
        logger.info(f"Revoked {count} sessions for user {user_id[:8]}***")
        return count

    # --- API Key Management ---

    def store_api_key(self, user_id: str, key_name: str, permissions: list = None) -> Dict[str, str]:
        """Generate and store an API key."""
        api_key = f"ak_{secrets.token_urlsafe(32)}"
        key_hash = self.protector.hmac_hash(api_key)
        redis_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        # Store only the hash and metadata, never the raw key
        key_data = {
            "user_id": user_id,
            "key_name": key_name,
            "key_prefix": api_key[:8],  # Store prefix for identification only
            "permissions": json.dumps(permissions or []),
            "created_at": datetime.utcnow().isoformat(),
            "last_used": None,
            "usage_count": 0,
        }

        serialized = json.dumps(key_data)

        def _store():
            pipe = self.redis.client.pipeline()
            pipe.setex(redis_key, API_KEY_TTL, serialized)
            # Index: map user to their API keys
            user_keys_index = f"{KEY_PREFIX_API_KEY}user:{self.protector.hash_for_key(user_id)}"
            pipe.sadd(user_keys_index, redis_key)
            pipe.expire(user_keys_index, API_KEY_TTL)
            pipe.execute()

        self.redis.execute_with_retry(_store)
        logger.info(f"API key '{key_name}' created for user {user_id[:8]}***")

        return {
            "api_key": api_key,
            "key_name": key_name,
            "expires_in": API_KEY_TTL,
        }

    def validate_api_key(self, api_key: str) -> Optional[Dict]:
        """Validate an API key and return associated data."""
        key_hash = self.protector.hmac_hash(api_key)
        redis_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        def _validate():
            data = self.redis.client.get(redis_key)
            if data:
                key_data = json.loads(data)
                # Update usage statistics
                key_data["last_used"] = datetime.utcnow().isoformat()
                key_data["usage_count"] = int(key_data.get("usage_count", 0)) + 1
                self.redis.client.setex(redis_key, API_KEY_TTL, json.dumps(key_data))
                return key_data
            return None

        result = self.redis.execute_with_retry(_validate)
        if result:
            logger.info(f"API key validated for user {result['user_id'][:8]}***")
        return result

    def revoke_api_key(self, api_key: str) -> bool:
        """Revoke an API key."""
        key_hash = self.protector.hmac_hash(api_key)
        redis_key = f"{KEY_PREFIX_API_KEY}{key_hash}"

        def _revoke():
            data = self.redis.client.get(redis_key)
            if data:
                key_data = json.loads(data)
                user_id = key_data.get("user_id", "")
                user_keys_index = f"{KEY_PREFIX_API_KEY}user:{self.protector.hash_for_key(user_id)}"
                pipe = self.redis.client.pipeline()
                pipe.delete(redis_key)
                pipe.srem(user_keys_index, redis_key)
                pipe.execute()
                return True
            return False

        result = self.redis.execute_with_retry(_revoke)
        logger.info(f"API key revocation: {'success' if result else 'not found'}")
        return result

    # --- User Profile Cache ---

    def cache_user_profile(self, user_id: str, profile_data: Dict) -> bool:
        """Cache user profile data with short TTL."""
        cache_key = f"{KEY_PREFIX_USER_PROFILE}{self.protector.hash_for_key(user_id)}"

        # Remove any highly sensitive fields before caching
        safe_fields = {"display_name", "email_hash", "role", "preferences", "avatar_url"}
        safe_data = {k: v for k, v in profile_data.items() if k in safe_fields}
        safe_data["cached_at"] = datetime.utcnow().isoformat()

        serialized = json.dumps(safe_data)

        def _cache():
            return self.redis.client.setex(cache_key, USER_PROFILE_CACHE_TTL, serialized)

        self.redis.execute_with_retry(_cache)
        return True

    def get_cached_user_profile(self, user_id: str) -> Optional[Dict]:
        """Retrieve cached user profile."""
        cache_key = f"{KEY_PREFIX_USER_PROFILE}{self.protector.hash_for_key(user_id)}"

        def _get():
            return self.redis.client.get(cache_key)

        raw_data = self.redis.execute_with_retry(_get)
        if raw_data:
            return json.loads(raw_data)
        return None

    def invalidate_user_profile(self, user_id: str) -> bool:
        """Invalidate cached user profile."""
        cache_key = f"{KEY_PREFIX_USER_PROFILE}{self.protector.hash_for_key(user_id)}"

        def _invalidate():
            return self.redis.client.delete(cache_key)

        self.redis.execute_with_retry(_invalidate)
        return True

    # --- Rate Limiting ---

    def check_rate_limit(self, identifier: str, max_requests: int = 100,
                         window_seconds: int = None) -> Dict[str, Any]:
        """Check and enforce rate limiting using sliding window."""
        window = window_seconds or RATE_LIMIT_TTL
        id_hash = self.protector.hash_for_key(identifier)
        rate_key = f"{KEY_PREFIX_RATE_LIMIT}{id_hash}"

        def _check():
            current = self.redis.client.get(rate_key)
            if current is None:
                pipe = self.redis.client.pipeline()
                pipe.setex(rate_key, window, 1)
                pipe.execute()
                return {"allowed": True, "remaining": max_requests - 1, "reset_in": window}

            current_count = int(current)
            if current_count >= max_requests:
                ttl = self.redis.client.ttl(rate_key)
                return {"allowed": False, "remaining": 0, "reset_in": max(ttl, 0)}

            new_count = self.redis.client.incr(rate_key)
            ttl = self.redis.client.ttl(rate_key)
            return {
                "allowed": True,
                "remaining": max(max_requests - new_count, 0),
                "reset_in": max(ttl, 0)
            }

        return self.redis.execute_with_retry(_check)

    # --- Temporary Secure Data Storage ---

    def store_temp_data(self, data: str, ttl: int = None) -> str:
        """Store temporary data with automatic expiration. Returns a retrieval token."""
        token = secrets.token_urlsafe(32)
        token_hash = self.protector.hash_for_key(token)
        redis_key = f"{KEY_PREFIX_TEMP}{token_hash}"

        # Obfuscate the data before storing
        protected_data = self.protector.obfuscate(data)
        effective_ttl = ttl or TEMP_DATA_TTL

        def _store():
            return self.redis.client.setex(redis_key, effective_ttl, protected_data)

        self.redis.execute_with_retry(_store)
        return token

    def retrieve_temp_data(self, token: str, delete_after_read: bool = True) -> Optional[str]:
        """Retrieve temporary data. Optionally delete after reading (one-time use)."""
        token_hash = self.protector.hash_for_key(token)
        redis_key = f"{KEY_PREFIX_TEMP}{token_hash}"

        def _retrieve():
            if delete_after_read:
                # Atomic get and delete
                pipe = self.redis.client.pipeline()
                pipe.get(redis_key)
                pipe.delete(redis_key)
                results = pipe.execute()
                return results[0]
            else:
                return self.redis.client.get(redis_key)

        protected_data = self.redis.execute_with_retry(_retrieve)
        if protected_data:
            return self.protector.deobfuscate(protected_data)
        return None


