def get_services():
    """Lazy initialization of services."""
    global redis_cluster_client, cache_service, data_protector
    if cache_service is None:
        data_protector = DataProtector(ENCRYPTION_KEY)
        redis_cluster_client = RedisClusterClient()
        cache_service = CacheService(redis_cluster_client, data_protector)
    return cache_service


def require_service_auth(f):
    """Decorator to require service-to-service authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing authorization"}), 401

        token = auth_header[7:]
        if not SERVICE_API_KEY:
            logger.warning("SERVICE_API_KEY not configured - skipping auth")
        elif not hmac.compare_digest(token, SERVICE_API_KEY):
            return jsonify({"error": "Invalid service credentials"}), 403

        return f(*args, **kwargs)
    return decorated


def require_session(f):
    """Decorator to validate session token from request."""
    @wraps(f)
    def decorated(*args, **kwargs):
        session_token = request.headers.get("X-Session-Token", "")
        if not session_token:
            return jsonify({"error": "Session token required"}), 401

        svc = get_services()
        session_data = svc.validate_session(session_token)
        if not session_data:
            return jsonify({"error": "Invalid or expired session"}), 401

        g.session_data = session_data
        g.user_id = session_data["user_id"]
        return f(*args, **kwargs)
    return decorated


