    """Create a new session."""
    data = request.get_json()
    if not data or "user_id" not in data:
        return jsonify({"error": "user_id is required"}), 400

    svc = get_services()

    # Rate limit session creation per user
    rate_check = svc.check_rate_limit(f"session_create:{data['user_id']}", max_requests=10, window_seconds=60)
    if not rate_check["allowed"]:
        return jsonify({"error": "Rate limit exceeded", "reset_in": rate_check["reset_in"]}), 429

    metadata = data.get("metadata", {})
    result = svc.create_session(data["user_id"], metadata)
    return jsonify(result), 201


