# --- Rate Limiting Endpoint ---

@app.route("/rate-limit/check", methods=["POST"])
@require_service_auth
def check_rate_limit():
    """Check rate limit for an identifier."""
    data = request.get_json()
    if not data or "identifier" not in data:
        return jsonify({"error": "identifier is required"}), 400

    svc = get_services()
    max_requests = data.get("max_requests", 100)
    window_seconds = data.get("window_seconds", RATE_LIMIT_TTL)
    result = svc.check_rate_limit(data["identifier"], max_requests, window_seconds)

    status_code = 200 if result["allowed"] else 429
    return jsonify(result), status_code


# --- Temporary Data Endpoints ---

@app.route("/temp-data", methods=["POST"])
@require_service_auth
def store_temp_data():
    """Store temporary sensitive data."""
    data = request.get_json()
    if not data or "data" not in data:
        return jsonify({"error": "data is required"}), 400

    svc = get_services()
    ttl = data.get("ttl", TEMP_DATA_TTL)
    # Cap TTL to prevent abuse
    ttl = min(ttl, 3600)

    token = svc.store_temp_data(data["data"], ttl)
    return jsonify({"retrieval_token": token, "expires_in": ttl}), 201


@app.route("/temp-data/retrieve", methods=["POST"])
@require_service_auth
def retrieve_temp_data():
    """Retrieve temporary data."""
    data = request.get_json()
    if not data or "token" not in data:
        return jsonify({"error": "token is required"}), 400

    svc = get_services()
    delete_after_read = data.get("delete_after_read", True)
    result = svc.retrieve_temp_data(data["token"], delete_after_read)

    if result is not None:
        return jsonify({"data": result}), 200
    return jsonify({"error": "Data not found or expired"}), 404


# --- Error Handlers ---

@app.errorhandler(500)
def internal_error(error):
    logger.error(f"Internal server error: {error}")
    return jsonify({"error": "Internal server error"}), 500


@app.errorhandler(404)
def not_found(error):
    return jsonify({"error": "Endpoint not found"}), 404


if __name__ == "__main__":
    # Validate required configuration
    if not ENCRYPTION_KEY:
        logger.error("ENCRYPTION_KEY environment variable is required!")
        logger.info("Set it with: export ENCRYPTION_KEY=$(python -c 'import secrets; print(secrets.token_hex(32))')")
        exit(1)

    port = int(os.environ.get("PORT", "8080"))
    debug = os.environ.get("FLASK_DEBUG", "false").lower() == "true"

    logger.info(f"Starting Cache Microservice on port {port}")
    logger.info(f"Redis nodes: {REDIS_NODES}")
    logger.info(f"SSL enabled: {REDIS_SSL}")
    logger.info(f"Session TTL: {SESSION_TOKEN_TTL}s, API Key TTL: {API_KEY_TTL}s")

    app.run(host="0.0.0.0", port=port, debug=debug)